def build_tower(x, y, z, height):
    for i in range(height):
        mc.setBlock(x, y + i, z, block.STONE.id)

pos = mc.player.getTilePos()
build_tower(pos.x, pos.y, pos.z, 10)

def build_line(length, block_id=block.STONE.id):
    pos = mc.player.getTilePos()
    for i in range(length):
        mc.setBlock(pos.x + i, pos.y, pos.z, block_id)

build_line(5)
build_line(8, block.GOLD_BLOCK.id)

